+	cleaned := filepath.Clean(filepath.FromSlash(path))
+	if filepath.IsAbs(cleaned) {
+		rel, err := filepath.Rel(filepath.Clean(workingDir), cleaned)
+		if err != nil {
+			return "", fmt.Errorf("invalid path")
+		}
+		cleaned = rel
+	}
